WOMT_aTexte['4_umfrage_text']=new Array();
WOMT_aTexte['4_umfrage_text'][0]='Wir würden aus wissenschaftlichen Gründen gerne mehr darüber erfahren, warum und mit welchen Folgen Sie den Wahl-O-Mat genutzt haben. Deswegen würden wir Sie bitten, an der folgenden anonymisierten Umfrage teilzunehmen. Sie wird rund fünf Minuten Ihrer Zeit in Anspruch nehmen. Vielen Dank für Ihre Mithilfe!';
WOMT_aTexte['4_umfrage_text'][1]='Vi vil af videnskabelige årsager rigtig gerne høre om, hvorfor du valgte at benytte Wahl-O-Mat og hvilke konsekvenser det havde for dig. Derfor beder vi dig om at deltage i denne opinionsunders☼gelse. Den er anonym og tager kun ca. fem minutter af din tid. Tusind tak for hjælpen!';
WOMT_aTexte['4_umfrage_text'][2]='Wi maad ütj wedenskapelk grünjer hal faan di wed, huaram dü di Wahl-O-Mat natigt heest an wat at di broocht hee. Diaram maad wi di bad, bi a kemen anonym amfraag mätumaagin. At wurt en  5 minüten düüre. Föl toonk al ens diarför!';
