WOMT_aTexte['3_text_unten']=new Array();
WOMT_aTexte['3_text_unten'][0]='<span class="wom_orange_star">*</span> Die Reihenfolge der Parteien richtet sich nach ihrem Wahlergebnis bei der letzten Wahl. Parteien, die daran nicht teilgenommen haben, erscheinen anschließend in alphabetischer Reihenfolge.';
WOMT_aTexte['3_text_unten'][1]='<span class="wom_orange_star">*</span> Partiernes rækkefølge afhænger af valgresultatet ved sidste valg. Partier, der ikke deltog, opføres efterfølgende i alfabetisk rækkefølge.';
WOMT_aTexte['3_text_unten'][2]='<span class="wom_orange_star">*</span> At räfulig faan a parteien racht ham efter hör resultoot bi a letst wool. Parteien, wat diar domools ei bi wiar, daage at aanj efter#apos#t alfabeet ap.';
WOMT_aTexte['0_intro_text_2']=new Array();
WOMT_aTexte['0_intro_text_2'][0]='Der Wahl-O-Mat ist keine Wahlempfehlung, sondern ein Informationsangebot über Wahlen und Politik.';
WOMT_aTexte['0_intro_text_2'][1]='Denne Wahl-O-Mat (valgkalkulator) er ikke en anbefaling til, hvem du skal stemme på, men giver dig nyttige informationer om valg og politik.';
WOMT_aTexte['0_intro_text_2'][2]='De Wahl-O-Mat as nian wool-emfeeling, oober en mögelkhaid, ham am woolen an politiik tu informiarin.';
WOMT_aTexte['3_text_partei_xvony']=new Array();
WOMT_aTexte['3_text_partei_xvony'][0]='Sie haben <span class="wom_counter"><strong>[ANZAHL]</strong> <span>von</span> [PARTEIMAX]</span> Parteien ausgewählt.';
